def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 1:
            penalty = 0
            for k in range(1, 5):
                for n in range(1, k+2):
                    penalty += ((ratio ** (3 * k + n)) / (k * n)) * ((-1)**(k+n))
            base = ratio ** 4 + (ratio ** 2) * 0.5
            priorities[i] = base + penalty
            if capacity > item * 2:
                priorities[i] *= 0.75
        elif 0 < ratio <= 1:
            score = 0
            toggle = True
            for j in range(1, 8):
                weight = (ratio ** j) * (j/7)
                score += weight if toggle else -weight
                toggle = not toggle
            multiplier = 20 if ratio < 0.25 else 12 if ratio < 0.5 else 7 if ratio < 0.75 else 3
            priorities[i] = abs(score) * multiplier
            extra = 0
            for m in range(1, 6):
                if m % 2 == 0:
                    extra += (np.log1p(ratio * m) / (m + 2))
                else:
                    extra += ((ratio ** m) / (m * 1.5))
            priorities[i] += extra
            if np.isclose(ratio, 0.5, atol=0.05):
                priorities[i] *= 0.9
            if capacity < item * 1.1:
                priorities[i] += 5
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
        if priorities[i] != np.inf:
            adjustment = 0
            for a in range(1, 4):
                factor = ((-1) ** a) * np.sin(ratio * a * np.pi) / (a + 1)
                adjustment += factor
            priorities[i] += abs(adjustment)
            if capacity % 2 == 0:
                priorities[i] *= 0.85
            else:
                priorities[i] *= 1.15
            if priorities[i] > 50:
                priorities[i] = 50 + np.log1p(priorities[i] - 50)
    return priorities
